import { useAuth0 } from "@auth0/auth0-react";
import { useCallback } from "react";
import { getEnv } from "@/utils/getEnv";

export function useAuth() {
  const { getAccessTokenSilently } = useAuth0();

  const getToken = useCallback(async () => {
    try {
      const env = getEnv(); 
      const audience = env.VITE_AUTH0_AUDIENCE;

      const token = await getAccessTokenSilently({
        authorizationParams: { audience },
      });

      // Vérification du format du token
      const parts = token.split(".");
      if (parts.length === 5) {
        console.warn("[Auth] Format JWE (token chiffré) ⚠️");
      } else if (parts.length !== 3) {
        console.warn("[Auth] Format token inattendu ⚠️");
      }

      return token;
    } catch (err) {
      console.error("Impossible de récupérer le token", err);
      throw err;
    }
  }, [getAccessTokenSilently]);

  return { getToken };
}

import { useMemo } from "react";
import { useAuth } from "@/hooks/useAuth";
import { getEnv } from "@/utils/getEnv"; 

const env = getEnv();
const API_ROOT = (env.VITE_API_URL || 'http://localhost:8080').replace(/\/$/, '');
const API_BASE = `${API_ROOT}/api/sellers`;

console.log("API_BASE sellers =", API_BASE);

export function useSellerService() {
  const { getToken } = useAuth();

  return useMemo(() => {
    const request = async (url, options = {}) => {
      const token = await getToken();
      const res = await fetch(url, {
        ...options,
        headers: {
          ...options.headers,
          Authorization: `Bearer ${token}`,
        },
      });
      const text = await res.text();

      if (!res.ok) {
        throw new Error(`Erreur ${res.status}: ${text}`);
      }

      try {
        return JSON.parse(text);
      } catch {
        return true; // pour les DELETE qui ne renvoient rien
      }
    };

    return {
      fetchMySeller: () => request(`${API_BASE}/me`),
      createSeller: (data) =>
        request(API_BASE, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(data),
        }),
      updateSeller: (id, data) =>
        request(`${API_BASE}/${id}`, {
          method: "PUT",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(data),
        }),
      deleteSeller: () => request(API_BASE, { method: "DELETE" }),
      checkIdentifier: (identifier, sellerId) =>
        request(`${API_BASE}/check-identifier?identifier=${identifier}${sellerId ? `&id=${sellerId}` : ''}`),
      testSmtpResend: (smtpData) =>
        request(`${API_BASE}/smtp/test-resend`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify(smtpData),
        }),
    };
  }, [getToken]);
}

import React, { useState } from 'react';
import { InputField, CheckboxField } from '@/components/form';
import { useSellerService } from '@/services/sellers';

export default function SmtpFields({ formData, handleChange, disabled, errors, setErrors }) {
  const [testing, setTesting] = useState(false);
  const [testResult, setTestResult] = useState(null);

  const sellerService = useSellerService();

  const smtp = formData.smtp || {};
  const isDisabled = disabled || !smtp.active;

  const handleCheckboxChange = (e) => {
    handleChange('smtp', { ...smtp, active: e.target.checked });

    if (!e.target.checked && setErrors) {
      setErrors((prev) => {
        const copy = { ...prev };
        delete copy.smtp_from;
        return copy;
      });
    }
  };

  const handleSmtpChange = (field, value) => {
    handleChange('smtp', { ...smtp, [field]: value });
  };

  const validateFields = () => {
    if (!smtp.active) return true;

    const newErrors = {};
    if (!smtp.smtp_from) newErrors.smtp_from = 'L’email d’expéditeur est requis';

    if (Object.keys(newErrors).length > 0) {
      setErrors?.((prev) => ({ ...prev, ...newErrors }));
      return false;
    }
    return true;
  };

  const handleTestConnection = async () => {
    if (!validateFields()) return;

    setTesting(true);
    setTestResult(null);

    try {
      const data = await sellerService.testSmtpResend({ smtp_from: smtp.smtp_from });

      if (data.success) {
        setTestResult({ success: true, message: 'Email envoyé ✅' });
      } else {
        setTestResult({ success: false, message: data.error || 'Erreur inconnue' });
      }
    } catch (err) {
      setTestResult({ success: false, message: err.message });
    } finally {
      setTesting(false);
    }
  };

  return (
    <div className="border p-3 rounded mb-3 bg-light">
      <CheckboxField
        id="smtp_active"
        name="active"
        label="Activer l’envoi d’emails"
        checked={smtp.active || false}
        onChange={handleCheckboxChange}
        disabled={disabled}
      />

      <InputField
        id="smtp_from"
        name="smtp_from"
        label="Email d’expéditeur"
        value={smtp.smtp_from || ''}
        onChange={(value) => handleSmtpChange('smtp_from', value)}
        disabled={isDisabled}
        error={errors?.smtp_from}
      />

      <button
        type="button"
        className="btn btn-outline-primary mt-2"
        onClick={handleTestConnection}
        disabled={isDisabled || testing}
      >
        {testing ? 'Envoi en cours...' : 'Envoyer un email de test'}
      </button>

      {testResult && (
        <div className={`mt-2 ${testResult.success ? 'text-success' : 'text-danger'}`}>
          {testResult.message}
        </div>
      )}
    </div>
  );
}

